targets.expr:
last_over_time(
  {user_unit="phar-liquidity-bot.service"}
  |= "Portfolio value:"
  | regexp `Portfolio value: [\d.]+ WAVAX \(\$(?P<value_usd>[\d.]+)\)`
  | unwrap value_usd [10m]
)

last_over_time(
  {user_unit="phar-liquidity-bot.service"}
  |= "Portfolio value:"
  | regexp `Portfolio value: (?P<wavax>[\d.]+) WAVAX`
  | unwrap wavax [10m]
)

last_over_time(
  {user_unit="phar-liquidity-bot.service"} 
  | regexp `Total reward collections: (?P<rewards>\d+)` 
  | unwrap rewards [1h]
)

last_over_time(
  {user_unit="phar-liquidity-bot.service"}
  |= "PHAR received"
  | regexp `cumulative: (?P<phar>[\d.]+) PHAR`
  | unwrap phar [10m]
)
